const fs = require\('fs'\);
const raw = fs.readFileSync\('mcp-synta-mcp-n8n_get_workflow-1773153100113.txt', 'utf8'\);
let data = JSON.parse\(raw\);
if \(data['0']\) data = data['0'];
const inner = JSON.parse\(data.text\);
const nodes = inner.data.nodes;

// Search ALL nodes \(not just Code\) for problematic patterns in their parameters
const patterns = ['\\\\\\$json[0]', '\\\\\\$json.length', 'items[0]', '\\\\\\$input.first\(\).json[0]'];

function searchObj\(obj, path\) {
  const results = [];
  if \(!obj\) return results;
  if \(typeof obj === 'string'\) {
    for \(const pat of patterns\) {
      if \(obj.includes\(pat.replace\(/\\\\\\\\\\\\\\\\/g, ''\)\)\) {
        // Check without escapes
      }
    }
    if \(obj.includes\('\\$json[0]'\) || obj.includes\('\\$json.length'\) || obj.includes\('items[0]'\) || obj.includes\('\\$input.first\(\).json[0]'\)\) {
      results.push\({ path, value: obj }\);
    }
  } else if \(Array.isArray\(obj\)\) {
    obj.forEach\(\(item, i\) => results.push\(...searchObj\(item, path + '[' + i + ']'\)\)\);
  } else if \(typeof obj === 'object'\) {
    for \(const key of Object.keys\(obj\)\) {
      results.push\(...searchObj\(obj[key], path + '.' + key\)\);
    }
  }
  return results;
}

console.log\('=== ALL NODES WITH PROBLEMATIC PATTERNS IN PARAMETERS ==='\);
console.log\('\(Excluding Code nodes jsCode, which were already listed\)'\);
console.log\(''\);

nodes.forEach\(n => {
  // Skip jsCode in code nodes \(already covered\)
  const params = JSON.parse\(JSON.stringify\(n.parameters || {}\)\);
  if \(n.type === 'n8n-nodes-base.code'\) {
    delete params.jsCode;
  }

  const matches = searchObj\(params, 'parameters'\);
  if \(matches.length > 0\) {
    console.log\('NODE: \\"' + n.name + '\\" \(type: ' + n.type + ', id: ' + n.id + '\)'\);
    matches.forEach\(m => {
      console.log\('  Path:', m.path\);
      console.log\('  Value:', m.value.substring\(0, 300\)\);
      console.log\(''\);
    }\);
  }
}\);
" 2>&1)

